import{_ as t,o as a,c as o,ag as r}from"./chunks/framework.BOaOek6C.js";const g=JSON.parse('{"title":"App shell (Md::AppShell)","description":"","frontmatter":{},"headers":[],"relativePath":"addons/md/components/app-shell.md","filePath":"addons/md/components/app-shell.md"}'),d={name:"addons/md/components/app-shell.md"};function s(n,e,l,i,c,p){return a(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="app-shell-md-appshell" tabindex="-1">App shell (<code>Md::AppShell</code>) <a class="header-anchor" href="#app-shell-md-appshell" aria-label="Permalink to &quot;App shell (`Md::AppShell`)&quot;">​</a></h1><h2 id="in-plain-language" tabindex="-1">In plain language <a class="header-anchor" href="#in-plain-language" aria-label="Permalink to &quot;In plain language&quot;">​</a></h2><p><strong>App shell</strong> is the outer frame of MdEditor: it reserves space for the <strong>left rail</strong>, the <strong>top navigation and title bars</strong>, the <strong>main work area</strong>, and an optional <strong>right sidebar</strong>. On phones and narrow windows, the left rail can slide in as an overlay.</p><h2 id="source-file" tabindex="-1">Source file <a class="header-anchor" href="#source-file" aria-label="Permalink to &quot;Source file&quot;">​</a></h2><p><code>addons/md/addon/components/md/app-shell.gjs</code></p><h2 id="what-the-host-app-must-provide" tabindex="-1">What the host app must provide <a class="header-anchor" href="#what-the-host-app-must-provide" aria-label="Permalink to &quot;What the host app must provide&quot;">​</a></h2><p>The shell uses <strong>named blocks</strong> (slots). The MdEditor <code>application</code> template passes:</p><table tabindex="0"><thead><tr><th>Slot</th><th>Typical content</th></tr></thead><tbody><tr><td><strong><code>left</code></strong></td><td>Brand, accordion nav, etc.</td></tr><tr><td><strong><code>primary</code></strong></td><td><code>Md::PrimaryNav</code></td></tr><tr><td><strong><code>context</code></strong></td><td><code>Md::ContextTitleBar</code></td></tr><tr><td><strong><code>right</code></strong></td><td>Secondary panels</td></tr><tr><td><strong>default</strong></td><td>The route outlet — where the current page’s template is rendered.</td></tr></tbody></table><h2 id="inputs-arguments" tabindex="-1">Inputs (arguments) <a class="header-anchor" href="#inputs-arguments" aria-label="Permalink to &quot;Inputs (arguments)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Argument</th><th>Purpose</th></tr></thead><tbody><tr><td><code>@leftSidebarOpen</code></td><td>Whether the left drawer should be treated as open on small screens (<code>true</code> / <code>false</code>).</td></tr><tr><td><code>@onCloseLeftSidebar</code></td><td>Action when the dimmed backdrop is clicked (should set sidebar closed).</td></tr><tr><td><code>@closeSidebarLabel</code></td><td>Accessible label for that backdrop control (e.g. translated “Close sidebar”).</td></tr></tbody></table><h2 id="logic-services" tabindex="-1">Logic &amp; “services” <a class="header-anchor" href="#logic-services" aria-label="Permalink to &quot;Logic &amp; “services”&quot;">​</a></h2><p><strong>None inside the addon.</strong> The shell only <strong>yields</strong> regions and wires <strong>click/keyboard</strong> affordances (e.g. backdrop). <strong>State</strong> (<code>leftSidebarOpen</code>, toggle actions) is implemented in the <strong>application</strong> layer.</p>',12)])])}const m=t(d,[["render",s]]);export{g as __pageData,m as default};
